                    if !all_fields.contains(&ilcf_then.as_str()) { all_fields.push(ilcf_then.as_str()); }
                    if !all_fields.contains(&ilcf_else.as_str()) { all_fields.push(ilcf_else.as_str()); }
                    let then_idx = all_fields.iter().position(|f| *f == ilcf_then.as_str()).unwrap();
                    let else_idx = all_fields.iter().position(|f| *f == ilcf_else.as_str()).unwrap();
                    let mut ranges_buf = vec![(0usize, 0usize); all_fields.len()];
