                                    match op { BinOp::Gt => val > threshold, BinOp::Lt => val < threshold, BinOp::Ge => val >= threshold, BinOp::Le => val <= threshold, BinOp::Eq => val == threshold, BinOp::Ne => val != threshold, _ => false }
